import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import Timer from './Timer';

const QuizPage = ({ quizId, teamInfo, onSubmit, onTimeout }) => {
  const [questions, setQuestions] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [submitting, setSubmitting] = useState(false);

  // Simple copy/paste disable
  useEffect(() => {
    const disableCopyPaste = (e) => {
      e.preventDefault();
      return false;
    };

    const disableKeys = (e) => {
      if (e.ctrlKey && (e.key === 'c' || e.key === 'v' || e.key === 'x')) {
        e.preventDefault();
        return false;
      }
      if (e.key === 'F12') {
        e.preventDefault();
        return false;
      }
    };

    document.addEventListener('contextmenu', disableCopyPaste);
    document.addEventListener('copy', disableCopyPaste);
    document.addEventListener('cut', disableCopyPaste);
    document.addEventListener('paste', disableCopyPaste);
    document.addEventListener('keydown', disableKeys);

    return () => {
      document.removeEventListener('contextmenu', disableCopyPaste);
      document.removeEventListener('copy', disableCopyPaste);
      document.removeEventListener('cut', disableCopyPaste);
      document.removeEventListener('paste', disableCopyPaste);
      document.removeEventListener('keydown', disableKeys);
    };
  }, []);

  // Tab switch detection
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden && !submitting) {
        setTabSwitchCount(prev => {
          const newCount = prev + 1;

          if (newCount === 1) {
            alert('⚠️ Warning: Tab switching is not allowed. One more violation will end your quiz.');
          }

          if (newCount >= 2) {
            alert('❌ Quiz ended due to tab switching violation. Submitting your answers...');
            setTimeout(() => handleSubmitQuiz(), 500);
          }

          return newCount;
        });
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [submitting]);

  // Prevent back button
  useEffect(() => {
    window.history.pushState(null, null, window.location.href);
    const handlePopState = () => {
      window.history.pushState(null, null, window.location.href);
      alert('⛔ Navigation is disabled during quiz');
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  // Fetch questions
  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const response = await axios.get(`http://localhost:8000/questions/${quizId}`);
        setQuestions(response.data.questions);
      } catch (err) {
        setError('Failed to load questions');
      } finally {
        setLoading(false);
      }
    };
    fetchQuestions();
  }, [quizId]);

  const handleSubmitQuiz = useCallback(async () => {
    if (submitting) return;

    setSubmitting(true);

    try {
      const answersList = Object.entries(answers).map(([qId, selected]) => ({
        question_id: parseInt(qId),
        selected_option: selected
      }));

      const response = await axios.post('http://localhost:8000/submit', {
        quiz_id: quizId,
        answers: answersList,
        tab_switch_count: tabSwitchCount
      });

      onSubmit({
        score: response.data.score,
        totalQuestions: response.data.total_questions,
        timeTaken: response.data.time_taken_microseconds
      });

    } catch (err) {
      alert('Failed to submit. Please try again.');
      setSubmitting(false);
    }
  }, [quizId, answers, tabSwitchCount, onSubmit, submitting]);

  const handleAnswerSelect = (questionId, option) => {
    if (submitting) return;

    setAnswers(prev => ({
      ...prev,
      [questionId]: option
    }));

    // Auto move to next question
    if (currentIndex < questions.length - 1) {
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
      }, 200);
    }
  };

  const handleSubmit = () => {
    if (Object.keys(answers).length !== questions.length) {
      alert(`Please answer all questions. (${Object.keys(answers).length}/${questions.length})`);
      return;
    }
    handleSubmitQuiz();
  };

  const handleTimeUp = () => {
    if (!submitting && Object.keys(answers).length > 0) {
      alert('⏰ Time is up! Submitting your answers...');
      handleSubmitQuiz();
      if (onTimeout) onTimeout();
    }
  };

  if (loading) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff',
        color: '#4a5568',
        fontSize: '18px'
      }}>
        Loading questions...
      </div>
    );
  }

  if (error || !questions.length) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: '#ffffff'
      }}>
        <div style={{ textAlign: 'center' }}>
          <p style={{ color: '#c53030', marginBottom: '20px', fontSize: '16px' }}>{error || 'No questions available'}</p>
          <button 
            onClick={() => window.location.reload()}
            style={{
              padding: '10px 24px',
              backgroundColor: '#1a202c',
              color: '#fff',
              border: 'none',
              borderRadius: '6px',
              fontSize: '15px',
              fontWeight: '500',
              cursor: 'pointer'
            }}
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  const currentQuestion = questions[currentIndex];
  const answeredCount = Object.keys(answers).length;

  return (
    <div style={{
      minHeight: '100vh',
      backgroundColor: '#ffffff',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center'
    }}>
      <div style={{
        width: '100%',
        maxWidth: '700px',
        padding: '40px 20px'
      }}>
        {/* Header */}
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '40px',
          paddingBottom: '15px',
          borderBottom: '1px solid #e2e8f0'
        }}>
          <div style={{ 
            fontSize: '17px',
            fontWeight: '500',
            color: '#2d3748'
          }}>
            Question <span style={{ color: '#1a202c', fontWeight: '600' }}>{currentIndex + 1}</span> of {questions.length}
          </div>
          <Timer 
            initialSeconds={1800}
            onTimeUp={handleTimeUp}
            isActive={!submitting}
          />
        </div>

        {/* Warning */}
        {tabSwitchCount === 1 && (
          <div style={{
            backgroundColor: '#fef5e7',
            color: '#b45f06',
            padding: '14px 18px',
            marginBottom: '30px',
            fontSize: '14px',
            borderRadius: '8px',
            border: '1px solid #f9d7a5'
          }}>
            ⚠️ <strong>Warning:</strong> Tab switching detected (1/2). Next violation will end your quiz.
          </div>
        )}

        {/* Question */}
        <div style={{ marginBottom: '40px' }}>
          <h2 style={{
            fontSize: '22px',
            fontWeight: '500',
            lineHeight: '1.6',
            marginBottom: '35px',
            color: '#1a202c'
          }}>
            {currentQuestion.question}
          </h2>

          {/* Options */}
          <div>
            {currentQuestion.options.map((option, idx) => {
              const isSelected = answers[currentQuestion.id] === option;
              const optionId = `opt_${currentQuestion.id}_${idx}`;

              return (
                <div
                  key={idx}
                  onClick={() => !submitting && handleAnswerSelect(currentQuestion.id, option)}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    marginBottom: '18px',
                    cursor: submitting ? 'default' : 'pointer',
                    padding: '8px 12px',
                    backgroundColor: isSelected ? '#f7fafc' : 'transparent',
                    borderRadius: '8px',
                    border: isSelected ? '1px solid #cbd5e0' : 'none'
                  }}
                >
                  <input
                    type="radio"
                    id={optionId}
                    name={`q_${currentQuestion.id}`}
                    checked={isSelected}
                    onChange={() => {}}
                    disabled={submitting}
                    style={{
                      width: '20px',
                      height: '20px',
                      marginRight: '14px',
                      cursor: submitting ? 'default' : 'pointer',
                      accentColor: '#1a202c'
                    }}
                  />
                  <label
                    htmlFor={optionId}
                    style={{
                      fontSize: '17px',
                      cursor: submitting ? 'default' : 'pointer',
                      color: isSelected ? '#1a202c' : '#2d3748',
                      fontWeight: isSelected ? '500' : '400'
                    }}
                  >
                    {option}
                  </label>
                </div>
              );
            })}
          </div>
        </div>

        {/* Footer */}
        <div style={{
          borderTop: '1px solid #e2e8f0',
          paddingTop: '24px',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <span style={{ 
            fontSize: '15px', 
            color: '#4a5568',
            fontWeight: '500'
          }}>
            Answered: <span style={{ color: '#1a202c', fontWeight: '600' }}>{answeredCount}</span>/{questions.length}
          </span>

          {answeredCount === questions.length && !submitting && (
            <button
              onClick={handleSubmit}
              style={{
                backgroundColor: '#1a202c',
                color: '#fff',
                border: 'none',
                padding: '12px 32px',
                borderRadius: '8px',
                fontSize: '16px',
                fontWeight: '600',
                cursor: 'pointer',
                transition: 'background-color 0.2s'
              }}
              onMouseEnter={(e) => e.target.style.backgroundColor = '#2d3748'}
              onMouseLeave={(e) => e.target.style.backgroundColor = '#1a202c'}
            >
              Submit Quiz
            </button>
          )}

          {submitting && (
            <span style={{ color: '#4a5568', fontSize: '15px' }}>Submitting your answers...</span>
          )}
        </div>
      </div>
    </div>
  );
};

export default QuizPage;
